import React, { useState } from "react";
import { useAuth } from "../../context/AuthContext";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./ProfileModal.css";

export default function ProfileModal({ onClose, initialTab = "info" }) {
  const [tab, setTab] = useState(initialTab);
  const { user, logout } = useAuth();
  const [form, setForm] = useState({
    name: user?.name || "",
    phoneNumber: user?.phoneNumber || "",
    address: user?.address || "",
    avatarUrl: user?.avatarUrl || "",
  });
  const [pwForm, setPwForm] = useState({ currentPassword: "", newPassword: "", confirm: "" });
  const [loading, setLoading] = useState(false);

  const handleUpdateInfo = async () => {
    setLoading(true);
    try {
      await api.put(`/users/${user.id}`, form);
      // Cập nhật localStorage
      const updated = { ...user, ...form };
      localStorage.setItem("user", JSON.stringify(updated));
      toast.success("Cập nhật thông tin thành công!");
      onClose();
    } catch (e) {
      toast.error(e.response?.data?.message || "Thất bại");
    } finally { setLoading(false); }
  };

  const handleChangePassword = async () => {
    if (pwForm.newPassword !== pwForm.confirm) { toast.error("Mật khẩu xác nhận không khớp"); return; }
    if (pwForm.newPassword.length < 6) { toast.error("Mật khẩu mới phải từ 6 ký tự"); return; }
    setLoading(true);
    try {
      await api.put(`/users/${user.id}/change-password`, {
        currentPassword: pwForm.currentPassword,
        newPassword: pwForm.newPassword
      });
      toast.success("Đổi mật khẩu thành công!");
      setPwForm({ currentPassword: "", newPassword: "", confirm: "" });
      onClose();
    } catch (e) {
      toast.error(e.response?.data?.message || "Mật khẩu hiện tại không đúng");
    } finally { setLoading(false); }
  };

  const ROLE_NAMES = { 1: "Admin", 2: "Giáo viên", 3: "Học viên" };

  return (
    <div className="profile-overlay" onClick={onClose}>
      <div className="profile-modal" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="profile-header">
          <div className="profile-avatar-big">
            {user?.avatarUrl
              ? <img src={user.avatarUrl} alt={user.name} />
              : <span>{user?.name?.charAt(0)?.toUpperCase()}</span>}
          </div>
          <div className="profile-header-info">
            <h3>{user?.name}</h3>
            <span className="profile-role-badge">{ROLE_NAMES[user?.roleId]}</span>
            <p>{user?.email}</p>
          </div>
          <button className="profile-close" onClick={onClose}>✕</button>
        </div>

        {/* Tabs */}
        <div className="profile-tabs">
          <button className={`ptab ${tab === "info" ? "active" : ""}`} onClick={() => setTab("info")}>
            👤 Thông tin
          </button>
          <button className={`ptab ${tab === "password" ? "active" : ""}`} onClick={() => setTab("password")}>
            🔒 Đổi mật khẩu
          </button>
        </div>

        {/* Tab Info */}
        {tab === "info" && (
          <div className="profile-body">
            <div className="pform-group">
              <label>Họ và tên</label>
              <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Nguyễn Văn A" />
            </div>
            <div className="pform-group">
              <label>Email</label>
              <input value={user?.email} disabled style={{ opacity: 0.6 }} />
              <span className="field-note">Không thể thay đổi email</span>
            </div>
            <div className="pform-group">
              <label>Số điện thoại</label>
              <input value={form.phoneNumber} onChange={e => setForm({ ...form, phoneNumber: e.target.value })} placeholder="0901234567" />
            </div>
            <div className="pform-group">
              <label>Địa chỉ</label>
              <input value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} placeholder="TP. Hồ Chí Minh" />
            </div>
            <div className="pform-group">
              <label>URL ảnh đại diện</label>
              <input value={form.avatarUrl} onChange={e => setForm({ ...form, avatarUrl: e.target.value })} placeholder="https://..." />
              {form.avatarUrl && (
                <img src={form.avatarUrl} alt="preview" className="avatar-preview"
                  onError={e => e.target.style.display = "none"} />
              )}
            </div>
            <button className="btn-profile-save" onClick={handleUpdateInfo} disabled={loading}>
              {loading ? <span className="spinner" /> : "💾 Lưu thay đổi"}
            </button>
          </div>
        )}

        {/* Tab Password */}
        {tab === "password" && (
          <div className="profile-body">
            <div className="pform-group">
              <label>Mật khẩu hiện tại</label>
              <input type="password" value={pwForm.currentPassword}
                onChange={e => setPwForm({ ...pwForm, currentPassword: e.target.value })}
                placeholder="Nhập mật khẩu hiện tại" />
            </div>
            <div className="pform-group">
              <label>Mật khẩu mới</label>
              <input type="password" value={pwForm.newPassword}
                onChange={e => setPwForm({ ...pwForm, newPassword: e.target.value })}
                placeholder="Tối thiểu 6 ký tự" />
            </div>
            <div className="pform-group">
              <label>Xác nhận mật khẩu mới</label>
              <input type="password" value={pwForm.confirm}
                onChange={e => setPwForm({ ...pwForm, confirm: e.target.value })}
                placeholder="Nhập lại mật khẩu mới" />
            </div>
            <button className="btn-profile-save" onClick={handleChangePassword} disabled={loading}>
              {loading ? <span className="spinner" /> : "🔒 Đổi mật khẩu"}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
